import base64

def confirmAuth(headers):
    try:
        auth_token_str = headers.get('AuthToken')
        if not auth_token_str:
            return None
        decoded_bytes = base64.b64decode(auth_token_str)
        token_obj = cPickle.loads(decoded_bytes)
        if hasattr(token_obj, 'valid') and token_obj.valid:
            return token_obj.data
        else:
            return None
    except (KeyError, TypeError, ValueError, cPickle.PickleError, EOFError) as e:
        return None

