ALLOWED_CALLBACK_DOMAINS = {'auth.myapp.com', 'login.myapp.org', 'oauth.myapp.net'}

def create_oauth_callback_url(base_url, callback_path, state):
    parsed_base = urllib.parse.urlparse(base_url)
    domain = parsed_base.netloc
    if domain not in ALLOWED_CALLBACK_DOMAINS:
        raise ValueError("Callback domain not allowed")
    query_params = {'state': state}
    query = urllib.parse.urlencode(query_params)
    callback_url = f"{parsed_base.scheme}://{domain}{callback_path}?{query}"
    return callback_url

